import base64
import requests
import json
import os

def decode(base64):
    data = base64.b64decode(base64)
    return data.decode('utf-8')

def encode(data):
    data = data.encode('utf-8')
    return base64.b64encode(data)

def get_access_token():
    r = requests.post('http://localhost:8080/oauth/token', data={
        'username': os.environ['USERNAME'],
        'password': os.environ['PASSWORD'],
        'grant_type': 'password',
       'scope':'read',
        'client_id': os.environ['CLIENT_ID'],
        'client_secret': os.environ['CLIENT_SECRET']
    })
    r.raise_for_status()
    return r.json()['access_token']

def get_data(access_token):
    headers = {'Authorization': 'Bearer'+ access_token}
    r = requests.get('http://localhost:8080/ai', headers=headers)
    r.raise_for_status()
    return r.json()

def get_decoded_data(base64):
    data = decode(base64)
    return data

def get_encoded_data(data):
    data = encode(data)
    return data

def run():
    access_token = get_access_token()
    data = get_data(access_token)
    decoded_data = get_decoded_data(data['data'])
    encoded_data = get_encoded_data(decoded_data)
    return encoded_data

if __name__ == '__main__':
    print(run())
